VALUES
  ('social-worker-moex-01121', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', 'Papell和Rothman提出團體工作的社會目標模式，下列敘述何者錯誤？', '["核心概念是社會意識與社會責任", "團體工作者的角色是有責任的使能者", "工作聚焦在成員創造一個自助、互助的體系", "社會目標模式的理論基礎來源眾多，其中包括佛洛伊德的人格理論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01122', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關開放式團體與封閉式團體的比較，下列敘述何者正確？', '["開放式團體的成效一定比封閉式團體差", "開放式團體較容易產生有創新的意見和資源", "開放式團體較容易產生凝聚力", "封閉式團體不會受到團體成員變動的影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01123', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在團體開始前，需要對團體成員公開的資訊，下列敘述何者錯誤？', '["成員保密之例外情況", "給予回顧與評論成員的機會", "成員取得其個人檔案資料的權益等資訊", "提供成員有關團體目標、團體限制，及處遇可能存在的危機之資訊"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01124', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '針對自助團體的敘述，下列何者正確？', '["成員參與自助團體後，其個人社會資本會產生變化，且參加越久，其社會資本得分越不理想", "自助團體拒絕或排斥專業的涉入和協助，成員間的互助關係是平等的同儕關係，不依賴「專家 知識」，而是「經驗知識」", "自助團體很強調自我管理，既然有管理的事實，組織上就有階級之分", "自助團體是實際且實用的，也是自願的，所以不論是何種自助團體都會永續久存"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01125', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者為住院病人辦理一個團體，這個團體是為成員出院做準備。團體中所有的成員都已經 超過70歲，社會工作者擬在聚會之間，選擇幾個活動方案，希望能刺激案主的生理和社會生活， 以準備回到社區生活。下列那一個方案活動在刺激治療效果相較於其他方案活動效果較弱？', '["社會工作者直接採用「討論目前情況或醫院事件」進行討論和分享", "讓成員一起做餐點給整個團體享用，再要求分享做此一事情所帶來的感受", "邀請成員分享他們過往生活記憶中美好的事情，再進行彼此間的支持與回饋", "成員三三兩兩聚在一起進行各小組有興趣的活動，例如：園藝、製作糕點、討論孩子或孫子等， 之後再進行整個團體的交流"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01126', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體進行過程中需要面對的倫理問題，下列敘述何者錯誤？', '["基於團體發展的需要及特殊性的考量，領導者有責任安排協同領導者或其他相關專業人員協助 帶領團體", "團體領導者宜兼顧成員在團體外的個人議題，適時改變團體討論主題", "領導者可以表露自己的價值觀，但應避免強迫成員接受，或強烈暗示成員順從", "領導者應具有敏感度，適時覺察並妥善處理團體內特殊成員，以保障其他成員的利益"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
