  ('social-worker-moex-01129', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不是社區組織工作之過程？', '["建立關係", "分析社區", "情境估量", "未來的圖像"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
